mapper.select:
SELECT
l.lecture_id    AS lectureId,
l.member_code   AS memberCode,
l.status,
l.lecture_type  AS lectureType,
l.lecture_name  AS lectureName,
mj.name         AS majorName,
pc.name         AS proName,
l.credit,
l.academic_year AS academicYear,
l.year,
l.semester,
(SELECT COUNT(*) FROM lecture WHERE is_del = false
AND member_code = #{memberCode}
AND status = #{req.status}
AND year = #{req.year}
AND semester = #{req.semester}
) AS totalCount,

FROM (
SELECT DISTINCT l.lecture_id
FROM lecture l
WHERE l.member_code = #{memberCode}
AND l.is_del = false
AND l.status = #{req.status}

    AND l.lecture_name LIKE CONCAT('%', #{req.lectureName}, '%')

AND l.year = #{req.year}
AND l.semester = #{req.semester}
ORDER BY l.lecture_id DESC
LIMIT #{req.size} OFFSET #{req.startIdx}
) paged
JOIN lecture l ON l.lecture_id = paged.lecture_id
LEFT JOIN professor_cache pc ON l.member_code = pc.member_code
LEFT JOIN major mj ON l.major_id = mj.major_id
LEFT JOIN lecture_schedule ls ON l.lecture_id = ls.lecture_id
LEFT JOIN classroom lr ON ls.room_id = lr.room_id
ORDER BY l.lecture_id DESC

SELECT
l.lecture_id    AS lectureId,
l.lecture_type  AS lectureType,
l.lecture_name  AS lectureName,
mj.name         AS majorName,
pc.name         AS proName,
l.credit,
l.academic_year AS academicYear,
l.year,
l.semester,

(SELECT COUNT(DISTINCT l2.lecture_id)
FROM course c2
JOIN lecture l2 ON c2.lecture_id = l2.lecture_id
WHERE c2.student_code = #{memberCode}
AND l2.status = 'APPROVED'
AND l2.year = #{req.year}
AND l2.semester = #{req.semester}
AND c2.created_at < #{req.createdBefore}
) AS totalCount,

FROM course c
JOIN lecture l                ON c.lecture_id = l.lecture_id
LEFT JOIN professor_cache pc  ON l.member_code = pc.member_code
LEFT JOIN major mj            ON l.major_id = mj.major_id

WHERE c.student_code = #{memberCode}
AND l.status = 'APPROVED'
AND l.year = #{req.year}
AND l.semester = #{req.semester}
AND c.created_at < #{req.createdBefore}
ORDER BY l.lecture_id DESC
LIMIT #{req.size} OFFSET #{req.startIdx}

SELECT l.lecture_id AS lectureId, l.major_id AS majorId, mj.name AS majorName, pc.name AS proName, l.year, l.semester, l.lecture_name AS lectureName, l.credit, l.lecture_type AS lectureType, l.ref_books AS refBooks, l.goal, l.weekly_plan AS weeklyPlan, l.academic_year AS academicYear, l.start_date AS startDate, l.end_date AS endDate,
FROM lecture l LEFT JOIN major mj ON l.major_id = mj.major_id LEFT JOIN professor_cache pc ON l.member_code = pc.member_code
WHERE l.lecture_id = #{lectureId}
